@* Step progress indicator bar *@

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative m-0 p-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i + 1;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isClickable = isCompleted && !isCurrent;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(!isCurrent && !isCompleted ? "dimmed" : "")"
                role="listitem">
                <button class="btn step-btn p-0 border-0 bg-transparent w-100 @(isClickable ? "" : "pe-none")"
                        disabled="@(!isClickable)"
                        @onclick="() => OnStepClicked.InvokeAsync(step)">
                    <div class="step-circle mx-auto d-flex align-items-center justify-content-center rounded-circle mb-1
                                @(isCurrent ? "bg-primary text-white" : "") 
                                @(isCompleted && !isCurrent ? "bg-success text-white" : "")
                                @(!isCurrent && !isCompleted ? "bg-light text-muted border" : "")">
                        @if (isCompleted && !isCurrent)
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            <span>@step</span>
                        }
                    </div>
                    <small class="step-label @(isCurrent ? "fw-bold text-primary" : "") @(!isCurrent && !isCompleted ? "text-muted" : "")">
                        @StepNames[i]
                    </small>
                </button>

                @if (i < StepNames.Count - 1)
                {
                    <div class="step-connector position-absolute @(CompletedSteps.Contains(step) ? "bg-success" : "bg-light")"></div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };
}

.step-indicator ol {
    counter-reset: step;
}

.step-circle {
    width: 36px;
    height: 36px;
    font-size: 0.85rem;
    font-weight: 600;
    transition: all 0.2s ease;
}

.step-label {
    font-size: 0.75rem;
    display: block;
}

.step-item {
    position: relative;
    z-index: 1;
}

.step-connector {
    height: 3px;
    top: 18px;
    left: calc(50% + 22px);
    right: calc(-50% + 22px);
    z-index: 0;
}

.step-btn:not(:disabled):hover .step-circle {
    transform: scale(1.1);
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.25);
}

.step-item.dimmed {
    opacity: 0.5;
}

@* Step progress indicator bar *@

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative m-0 p-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i + 1;
