@page "/apply"
@rendermode InteractiveServer
@using sv_8f70346376b04ef183c03767197f2d68.Components.Pages.Apply

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo"
                                  ErrorMessage="@errorMessage"
                                  OnNext="NextStep" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries"
                                 ErrorMessage="@errorMessage"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 3:
                <ReferencesStep References="references"
                                ErrorMessage="@errorMessage"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 4:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 CoverLetterChanged="val => coverLetter = val"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 5:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            OnEditSection="GoToStep"
                            OnSubmit="Submit"
                            OnBack="PreviousStep"
                            IsSubmitting="isSubmitting"
                            Submitted="submitted"
                            ApplicationId="applicationId"
                            ErrorMessage="@errorMessage" />
                break;
        }
    </div>
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceModel> references = new() { new(), new() };
    private string coverLetter = "";

    private bool isSubmitting;
    private bool submitted;
    private int? applicationId;
    private string? errorMessage;

    private Task GoToStep(int step)
    {
        if (completedSteps.Contains(step))
        {
            errorMessage = null;
            currentStep = step;
        }
        return Task.CompletedTask;
    }

    private async Task NextStep()
    {
        errorMessage = null;

        if (!ValidateCurrentStep())
            return;

        completedSteps.Add(currentStep);

        if (currentStep < 5)
            currentStep++;
    }

    private void PreviousStep()
    {
        errorMessage = null;
        if (currentStep > 1)
            currentStep--;
    }

    private bool ValidateCurrentStep()
    {
        switch (currentStep)
        {
            case 1:
                if (string.IsNullOrWhiteSpace(personalInfo.FullName) ||
                    string.IsNullOrWhiteSpace(personalInfo.Email) ||
                    string.IsNullOrWhiteSpace(personalInfo.Phone) ||
                    string.IsNullOrWhiteSpace(personalInfo.Address))
                {
                    errorMessage = "Please fill in all required fields.";
                    return false;
                }
                return true;

            case 2:
                foreach (var entry in workEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company) ||
                        string.IsNullOrWhiteSpace(entry.Title) ||
                        entry.StartDate is null)
                    {
                        errorMessage = "Please fill in the company, title, and start date for all positions.";
                        return false;
                    }
                }
                return true;

            case 3:
                foreach (var r in references)
                {
                    if (string.IsNullOrWhiteSpace(r.Name) ||
                        string.IsNullOrWhiteSpace(r.Relationship) ||
                        string.IsNullOrWhiteSpace(r.Email) ||
                        string.IsNullOrWhiteSpace(r.Phone))
                    {
                        errorMessage = "Please fill in all fields for each reference.";
                        return false;
                    }
                }
                return true;

            case 4:
                if (string.IsNullOrWhiteSpace(coverLetter))
                {
                    errorMessage = "Please write a cover letter.";
                    return false;
                }
                return true;

            default:
                return true;
        }
    }

    private async Task Submit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            submitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

